import urllib.request, re, json

def get_video_data(video_id):
    url = f'https://www.youtube.com/watch?v={video_id}'
    headers = {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
        'Accept-Language': 'en-US,en;q=0.9',
    }
    req = urllib.request.Request(url, headers=headers)
    resp = urllib.request.urlopen(req, timeout=15)
    html = resp.read().decode('utf-8', errors='replace')

    # Try to find ytInitialData
    match = re.search(r'ytInitialData\s*=\s*({.*?});', html, re.DOTALL)
    if match:
        data = json.loads(match.group(1))
        # Extract description from the response
        try:
            desc = data['contents']['twoColumnWatchNextResults']['results']['results']['contents']
            for item in desc:
                if 'videoSecondaryInfoRenderer' in item:
                    desc_text = item['videoSecondaryInfoRenderer']['description']['runs']
                    full_desc = ''.join([r.get('text', '') for r in desc_text])
                    return full_desc
        except Exception as e:
            pass

    # Try to find description in ytInitialPlayerResponse
    match2 = re.search(r'ytInitialPlayerResponse\s*=\s*({.*?});', html, re.DOTALL)
    if match2:
        data2 = json.loads(match2.group(1))
        try:
            return data2['videoDetails']['shortDescription']
        except:
            pass

    return 'NO_DESC_FOUND'

